// ListProducts queries the database for products sorted by a specific column and direction.
func ListProducts(db *sql.DB, orderBy string, sortDir string) ([]Product, error) {
	if db == nil {
		return nil, fmt.Errorf("db is nil")
	}

	allowedOrderBy := map[string]string{
		"id":    "id",
		"name":  "name",
		"price": "price",
	}

	column, ok := allowedOrderBy[strings.ToLower(strings.TrimSpace(orderBy))]
	if !ok {
		column = "id"
	}

	dir := strings.ToUpper(strings.TrimSpace(sortDir))
	if dir != "ASC" && dir != "DESC" {
		dir = "ASC"
	}

	query := fmt.Sprintf("SELECT id, name, price FROM products ORDER BY %s %s", column, dir)

	rows, err := db.Query(query)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var products []Product
	for rows.Next() {
		var p Product
		if err := rows.Scan(&p.ID, &p.Name, &p.Price); err != nil {
			return nil, err
		}
		products = append(products, p)
	}

	if err := rows.Err(); err != nil {
		return nil, err
	}

	return products, nil
}

